		if (this.instanceSettings.isLeader) {
			this.logger.info(' ================================');
			this.logger.info('   Start Active Workflows:');
			this.logger.info(' ================================');
		}

		const batches = chunk(dbWorkflowIds, this.workflowsConfig.activationBatchSize);

